 1	import * as React from 'react';
 2	import { useController, UseControllerProps } from 'react-hook-form';
 3	import {
 4	  FormGroup,
 5	  FormGroupProps,
 6	  FormHelperText,
 7	  HelperText,
 8	  HelperTextItem,
 9	  HelperTextItemProps,
10	  ValidatedOptions,
11	} from '@patternfly/react-core';
12	
13	export type FormGroupControllerRenderProps = {
14	  value: any;
15	  validated: HelperTextItemProps['variant'];
16	  onChange: (...event: any[]) => void;
17	  onBlur: () => void;
18	};
19	
20	export type FormGroupControllerProps = UseControllerProps & {
21	  formGroupProps: FormGroupProps & {
22	    helperText?: string;
23	  };
24	  render: (props: FormGroupControllerRenderProps) => React.ReactNode;
25	};
26	
27	const FormGroupController: React.FC<FormGroupControllerProps> = ({
28	  formGroupProps,
29	  render,
30	  ...controllerProps
31	}) => {
32	  const {
33	    field: { value, onChange, onBlur },
34	    fieldState: { error, isDirty },
35	    formState: { isSubmitted },
36	  } = useController(controllerProps);
37	  const [validated, setValidated] =
38	    React.useState<HelperTextItemProps['variant']>('default');
39	
40	  React.useEffect(() => {
41	    setValidated(
42	      isDirty || isSubmitted ? (error ? 'error' : 'success') : 'default'
43	    );
44	  }, [error, isDirty, isSubmitted]);
45	
46	  return (
47	    <FormGroup id={controllerProps.name} {...formGroupProps}>
48	      {render({ value, validated, onChange, onBlur })}
49	      <FormHelperText>
50	        <HelperText>
51	          <HelperTextItem variant={validated}>
52	            {validated === ValidatedOptions.error && error?.message}
53	            {validated === ValidatedOptions.default &&
54	              formGroupProps?.helperText}
55	          </HelperTextItem>
56	        </HelperText>
57	      </FormHelperText>
58	    </FormGroup>
59	  );
60	};
61	
62	export default FormGroupController;

